const Q_PHYSICS_2003=[{"id": "objective>Physics>2003>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bead travelling on a straight wire is brought to rest at 0.2m by friction. If the mass of the bead is 0.01kg and the coefficient of  <br/> friction between the bead and the wire is 0.1, determine the work done by the friction.  <br/>  <br/>  [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass of bead = 0.01kg <br/> Coefficient of friction = 0.1 <br/> Workdone by friction = Frictional force × distance --------------- * <br/> Recall: Frictional force = U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">mg</span> <br/> F = 0.1 × 0.01 × 10 <br/> F = 0.01N <br/> W = 0.01 × 0.2 = 0.0002J = 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>J</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2003>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On top of a spiral spring of force constant 500 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is placed a mass of 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg. If the spring is compressed downwards by a length of 0.02m and then released, calculate the height to which the mass is projected.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Force constant, k = 500Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> mass, m = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg <br/> compression, e = 0.02m <br/> NOTE: The elastic potential of the spring is converted to the potential energy of the mass <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">ke<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mgh</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">500</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(0.02)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">h</td></tr></table></div> <br/> 250 × 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × h <br/> 1000 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × h <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span><hr size=\"1\" />5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> <br/> h = 0.2 × 10 = 2.0m         </div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2003>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A test tube of radius 1.0cm is loaded to 8.8g. If it is placed upright in water, find the depth to which it would sink.  <br/>  [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">–2</span>; density of water = 1000 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.8cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.2cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.0cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the question, it implies that the test tube floats in water. Recall that when a substance floats in a fluid, it displaces a weight of the fluid which is equal to its own weight, i.e upthrust equals weight <br/> U = W ----------------------- * <br/> ressure = F/A = pgh, where p = density, h = depth and g = 10ms-2 <br/> But F = P x A <br/> ∴ Force exerted by the load test tube = cross-sectional Area x Pressure <br/> i.e F = A x pgh <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∴h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />A</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">pg</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mg<hr size=\"1\" />AxPxg</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">8.8x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>x10<hr size=\"1\" />πr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>xpxg</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8.8x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>x10<hr size=\"1\" />πx(1.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>x1000x10</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/>  = 0.028m or 2.8cm</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>2003>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>   <br/> The length of a piece of glass block was measured by means of a vernier caliper as shown above. The length of the glass block is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.63cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.64cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.65cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.66cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Main scale reading = 1.60cm <br/> Vernier scale reading = 0.04cm <br/> Vernier caliper reading = 1.60 + 0.04 = 1.64cm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2003>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hose of cross-sectional area 0.5m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> is used to discharge water from a water tanker at a velocity of 60ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in 20s into a container.   <br/> If the container is filled completely, the volume of the container is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">240m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">600m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2400m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6000m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Cross-sectional area, A = 0.5m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> -------------------- * <br/> Velocity, V = 60ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> time, t = 20s <br/> Distance covered = 60 × 20 = 1200m <br/> Distance covered = Length = 1200m <br/> Volume filled within 20s = 1200 × 0.5 <br/>  = 600m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> From V = A × L</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2003>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an object just begins to slide on a surface inclined at 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the horizontal,the coefficient of friction is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">√ 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">√ 3/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/ √ 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/ √ 3</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2003/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Coefficient</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">friction</td><td style=\"text-align:center;\">for</td><td style=\"text-align:center;\">an</td><td style=\"text-align:center;\">inclined</td><td style=\"text-align:center;\">plane</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Wsinθ<hr size=\"1\" />Wcosθ</td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">µ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">tanθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">tan30</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />√3</td></tr></table></div></div>", "topic": "FRICTION"}, {"id": "objective>Physics>2003>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 100N is used to kick a football of mass 0.8kg. Find the velocity with which the ball moves if it takes 0.8s to be kicked.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">32ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">64ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given; <br/> Force, F = 100N  <br/> Mass, m = 0.8kg    <br/> Velocity, V = unknown <br/>  Initial velocity, U = 0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Time, t = 0.8s <br/> Recall: From Newton's Second Law <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m(v-u)<hr size=\"1\" />t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.8(v-u)<hr size=\"1\" />0.8</td></tr></table></div> <br/> 100 = v - u <br/> 100 = v - 0 <br/> v = 100ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2003>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water does not drop through an open umbrella of silk material unless the inside of the umbrella is touched. This is due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capillarity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmotic pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">viscosity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface tension</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is due to surface tension. Surface tension is the tension or force that enables some surface to behave like an elastic membrane.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2003>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stylus of a phonograph record exerts a force of 7.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>N on a groove of radius 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>m.  Compute the pressure exerted by the  <br/> stylus on the groove.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.45 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.45 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.90 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.42 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given, <br/> Force, F = 7.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>N <br/> radius, r = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>m <br/> Pressure, P = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />πr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.7×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span><hr size=\"1\" />3.142×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.7×7<hr size=\"1\" />22</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.45</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div></div>", "topic": "PRESSURE"}, {"id": "objective>Physics>2003>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of stone attached to one end of a string is whirled round in a horizontal circle and the string suddenly cuts. The stone will fly off in  <br/> a direction</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perpendicular to the circular path</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parallel to the circular path</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tangential to the circular path</div>", "<div style=\"font-family:Cambria;font-size:17px;\">towards the centre of the circle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2003/2.png\" style=\"position:relative;max-width:100%;\"/> <br/> Once the string cuts off, the stone moves off in a direction which is tangential to the original circular path.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2003>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 90cm uniform lever has a load of 30N suspended at 15cm from one of it sends. If the fulcrum is at the centre of gravity, the force   <br/> that must be applied at its other end to keep it in horizontal equilibrium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2003/3.png\" style=\"position:relative;max-width:100%;\"/> <br/> F x 45 = 900N; <br/> F = 900/45 = 20N.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS~~SIMPLE MACHINES"}, {"id": "objective>Physics>2003>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>   <br/> The  figure  above  shows  two  velocities V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span> and V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span>  <br/>  <br/>  Which  of  the  following diagrams  correctly  represents  the  <br/> vector difference W<span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span>= V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span>- V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: W = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> --------------------- * <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = W + V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> It implies that V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is the resultant of W and V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <img src=\"2003/4.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2003>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A satellite is in a parking orbit if its period is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less than the period of the earth.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more than the period of the earth.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to the period of the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the square of the period of the earth</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A satellite is in a parking orbit if its period is equal to the period of the earth. This is because a parking orbit is a temporary orbit used during the launch of a satellite or other space probe, which is usually a highly elliptical orbit with the same orbital period as the target orbit.</div>", "topic": "GRAVITATIONAL FIELD : PARKING ORBIT AND WEIGHTLESSNESS"}, {"id": "objective>Physics>2003>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">T(°C) </td><td style=\"border:1px solid black;text-align:center;\">   s.v.p (mm Hg)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">0 </td><td style=\"border:1px solid black;text-align:center;\">   4.58</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5  </td><td style=\"border:1px solid black;text-align:center;\">  6.51</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">10  </td><td style=\"border:1px solid black;text-align:center;\">  8.94</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">15  </td><td style=\"border:1px solid black;text-align:center;\">  12.67</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">20  </td><td style=\"border:1px solid black;text-align:center;\">  17.50</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40  </td><td style=\"border:1px solid black;text-align:center;\">  55.10</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60  </td><td style=\"border:1px solid black;text-align:center;\">  149.00</td></tr></table></div>The table above shows the saturation vapour pressure against temperature in a certain town. If the vapour pressure in this town at 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is 10 mmHg, what is the relative humidity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">170.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">57.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Relative</td><td style=\"text-align:center;\">humidity at a given temperature </td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Vapour pressure<hr size=\"1\" />Saturated vapour pressure</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />17.50</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">57.14%</td></tr></table></div></div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2003>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tuning fork of frequency 340Hz is vibrated just above a cylindrical tube of height 1.2m. If water is slowly poured into the  <br/> tube, at what maximum height will resonance occur? <br/> [Speed of sound in air = 340ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>].</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.95m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.60m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.45m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of sound in air is given as 340ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and the frequency of the tuning fork is also 340Hz. The wavelength of the sound produced by the tuning fork can be calculated using the formula: wavelength = speed of sound / frequency. This gives a wavelength of 1m. For resonance to occur in the tube, the length of the tube must be a multiple of the wavelength/4 (since it's a closed tube and the first resonance occurs at a quarter of the wavelength). The maximum height for resonance to occur is therefore 1m/4 = 0.25m. However, since the tube is already 1.2m high, the water must be filled up to 1.2m - 0.25m = 0.95m for the first resonance to occur. Hence, the correct option is 0.95m.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : RESONANCE"}, {"id": "objective>Physics>2003>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By what factor will the size of an object placed 10cm from a convex lens be increased if the image is seen on a screen placed 25cm from the lens?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The magnification (m) of a lens is given by the formula m = image distance / object distance. In this case, the object is placed 10cm from the lens and the image is seen on a screen placed 25cm from the lens. Therefore, the magnification is m = 25cm / 10cm = 2.5. This means the size of the object will be increased by a factor of 2.5. Hence, the correct option is 2.5.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2003>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Thermal equilibrium between two objects exists when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the temperatures of both objects are equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the  quantity  of  heat  in  both objects is the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the  heat  capacities  of  both objects are the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one object loses heat continuously to the other</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the zeroth law of thermodynamics, two bodies are in a state of thermal equilibrium if they have the same temperature. At this point of thermal equilibrium, the flow of heat stops, this forms the principle of operation of a thermometer. <br/> a)  <br/> <img src=\"2003/5.png\" style=\"position:relative;max-width:100%;\"/> <br/> Heat flows from the hot body to the colder body. <br/> b) <br/> <img src=\"2003/6.png\" style=\"position:relative;max-width:100%;\"/> <br/> Heat flow stops since the two bodies are in a state of thermal equilibrium.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2003>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An open pipe closed at one end produces its first fundamental note. If the velocity of sound in air is  v and l the length of the pipe, the  <br/> frequency of the note is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2V/L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V/5L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V/4L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V/2L</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the fundamental overtone <br/> <img src=\"2003/7.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L</td></tr></table></div> <br/> λ = 4L -------------- * <br/> Recall: v = fλ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />4L</td></tr></table></div></div>", "topic": "CHARACTERISTICS OF SOUND WAVES : FREQUENCY OF A NOTE EMITTED BY AIR COLUMNS"}, {"id": "objective>Physics>2003>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that Young's modulus for aluminium is 7.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>and density is 2.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, find the speed of the sound produced if a solid bar is struck at one end with a hammer.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Young's Modulus, E = 7.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Density, ρ = 2.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Speed, V = Unknown <br/> Recall: The speed, V of sound in a solid medium is given as: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">E<hr size=\"1\" />ρ</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span><hr size=\"1\" />2.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2.59 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>&nbsp;</span> <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">25.9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>&nbsp;</span> <br/> V = 5.1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> --------------------------- *</div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2003>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On a fairly cool rainy day when the temperature is 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, the length of a steel rail road track is 20cm. What will be its length on a hot dry day when the temperature is 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C?  <br/> [Coefficient of linear expansion of steel= 11 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>].</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20.013m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.009m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.004m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.002m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20°C <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 40°C <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20m <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = unknown <br/> α = 11 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td></tr></table></div> <br/> αL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ + L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ----------------- * <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 11 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 20 × 20 + 20 <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 400 × 11 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> + 20 <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> + 20 <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.0044 + 20 <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 20.0044m</div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2003>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an object is placed between two parallel plane mirrors with the reflecting  surfaces facing  each other, how many images of the object  <br/> will be formed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Infinite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Four</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Two.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If two mirrors are placed parallel to each other, it means the angle between them is zero degrees (0°). <br/> Recall: If two mirrors are inclined at an angle to each other, the number of images formed is given as  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360<hr size=\"1\" />θ</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360<hr size=\"1\" />0</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∞</td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2003>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon whereby the water droplets in the atmosphere combine with dust particles in the air to reduce visibility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cloud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fog</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon whereby the water droplets in the atmosphere combine with dust particles in the air to reduce visibility is the fog.</div>", "topic": "VAPOURS"}, {"id": "objective>Physics>2003>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what position will an object be placed in front of a concave mirror in order to obtain an image at infinity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At the pole of the mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the principal focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the centre of curvature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between the principal focus and the centre of curvature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the image to be formed at infinity from a concave mirror,the object must be placed at the principal focus.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>2003>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the distance from a point source of sound is doubled, by what factor does the intensity decrease?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall; <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> NOTE: λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> ----------------- * * <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(2λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> 4E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2003>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 2000W electric heater is used to heat a metal object of mass 5kg initially at 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. If a temperature rise of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is obtained after 10 minutes, the heat capacity of the material is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/>  <br/> Power, P = 2000W <br/>  <br/> Mass, m = 5kg <br/>  <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10°C <br/>  <br/> Δθ = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 30°C (<strong>NB:</strong> 30°C is not the final temperature) <br/>  <br/>  = 20°C <br/>  <br/> Time, t = 10 minutes = 600s <br/>  <br/> Electrical energy is converted to thermal energy <br/>  <br/> P × t = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>Δθ <br/>  <br/> 2000 × 600 = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> × 30 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000 × 600<hr size=\"1\" />30</td></tr></table></div> <br/>  <br/> ∴ C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 4.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>C</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2003>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J of heat energy is given off in 1 sec from a vessel maintained at a temperature gradient of 30km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the surface area of the vessel is <br/>  <br/> [Thermal conductivity, k = 400Wm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Energy, E = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J <br/> Time, t = 1.0s <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">temperature</td><td style=\"text-align:center;\">gradient,</td><td style=\"text-align:center;\">Δ<hr size=\"1\" />l</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div> <br/> Surface area = unknown  <br/> Thermal conductivity, k = 400Wm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Thermal</td><td style=\"text-align:center;\">conductivity</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Heat Energy<hr size=\"1\" />Time × Area × Temp.gradient</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">400</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span><hr size=\"1\" />1 × A × 30</td></tr></table></div> <br/> 120 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × A = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/> A = 1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "HEAT TRANSFER : TEMPERATURE GRADIENT, THERMAL CONDUCTIVITY AND HEAT FLUX"}, {"id": "objective>Physics>2003>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A positively charged rod X is brought near an uncharged metal sphere Y and is then touched by a finger with X still in place. When the  <br/> finger is removed, the result is that Y has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">no charge and a zero potential</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a positive charge and a zero potential</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a negative charge and a positive potential</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a negative charge and a negative potential</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2003/8.png\" style=\"position:relative;max-width:100%;\"/> <br/> What happens is that when the finger (a conductor) connects the two spheres in question, it transfers/conducts negative charges from the neutral sphere (Y) to the charged sphere. At the end of the day, Y becomes electron deficit (negative charged).</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2003>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/>   <br/> In the diagram above, if each of the resistors  can  dissipate  a maximum of 18W  without becoming excessively heated, what is the   <br/> maximum power the circuit can dissipate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">27W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5W.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2003/9.png\" style=\"position:relative;max-width:100%;\"/> <br/> It is given that the power dissipated by each resistor = 18W <br/> From the relation power, P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R, the current in the 2Ω series resistor is given by: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<hr size=\"1\" />R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9</td></tr></table></div> <br/> I = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">9&nbsp;</span> = 3A <br/> The effective parallel arrangement of the two 2Ω resistors:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1Ω</td></tr></table></div> <br/> ∴ Total resistance in the circuit = 1 + 2 = 3Ω <br/> current flowing the circuit = 3A <br/> ∴ Maximum power = P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R = 3<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> x 3 = 27W</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2003>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The operation of an optical fibre is based on the principle of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dispersion of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization of light</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The operation of an optical fibre is based on the principle of total internal reflection, which is a phenomenon that occurs when a propagating wave strikes a medium boundary at an angle larger than a particular critical angle with respect to the normal to the surface. This is a special case of refraction. Therefore, the correct answer is 'refraction of light'.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2003>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>   <br/> In the diagram above, what would happen to the current, I, if another resistor,  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, is connected in parallel to R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It will increase because the equivalent resistance will increase.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It will decrease if R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is greater thanR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It will increase because the effective resistance will decrease.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It will decrease if R2 is less than R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When another resistor is connected in parallel, the resistance (over all) decreases and the current increases.</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2003>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ray of light is incident on an equilateral triangular prism of refractive index 3/2. Calculate the angle through which the ray is minimally deviated in the prism.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">37.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">42.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin(A+d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>/2)<hr size=\"1\" />sin(A/2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin(60+d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>/2)<hr size=\"1\" />sin(60/2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin(60+d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>/2)<hr size=\"1\" />sin(30)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin(60 + d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>/2)<hr size=\"1\" />0.5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin(</td><td style=\"text-align:center;\">60 + d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60 + d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>(</td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60 + d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">48.59</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">97.18</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">37.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2003>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wire of 5Ω resistance is drawn out so that its new length is two times the original length. If the resistivity of the wire remains the same and the cross sectional  area is halved, the new resistance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5Ω</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a wire is drawn, the volume remains constant <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div>  <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 5Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5×A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>×A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/2<hr size=\"1\" />2L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R/2<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 20Ω</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2003>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electron of charge 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C is accelerated between two metal plates.If the kinetic energy of the electron is 4.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span>J,   <br/> the potential difference between the plates is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400V</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\"> = </td><td style=\"text-align:center;\">1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> </td><td style=\"text-align:center;\"> CK.E </td><td style=\"text-align:center;\"> = </td><td style=\"text-align:center;\"> 4.8 </td><td style=\"text-align:center;\"> x </td><td style=\"text-align:center;\"> 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span>J    P.D</td><td style=\"text-align:center;\"> = </td><td style=\"text-align:center;\">W<hr size=\"1\" />Q</td><td style=\"text-align:center;\"> = </td><td style=\"text-align:center;\">4.8</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span></td><td style=\"text-align:center;\">J<hr size=\"1\" />1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C</td><td style=\"text-align:center;\"> = </td><td style=\"text-align:center;\">3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>V </td><td style=\"text-align:center;\"> = </td><td style=\"text-align:center;\"> 300V</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2003>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A magnetic field is said to exist at a point if a force is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exerted on a stationary charge at the point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exerted on a moving  charge at the point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deflected at the point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strengthened at the point</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A magnetic field is said to exist it a point if a force is exerted on a moving charge at the point; F = BqV.</div>", "topic": "MAGNETIC FIELD : FORCE ON A CURRENT-CARRYING CONDUCTOR"}, {"id": "objective>Physics>2003>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. It retains its magnetism much longer than steel.  <br/> II. It is more easily magnetized than steel.  <br/> III. It is more easily demagnetized than steel.  <br/> IV. It produces a stronger  magnet than steel.  <br/> Which combination of the above makes iron preferable to steel in the making of electro-magnets?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II (Iron is more easily magnetized than steel) – This makes iron a better choice because it can quickly acquire a magnetic field when subjected to an external magnetic influence. <br/> III (Iron is more easily demagnetized than steel) – This is an advantage in electromagnets because you want the magnetism to disappear once the current is turned off. <br/> IV (Iron produces a stronger magnet than steel) – Iron is capable of producing a stronger magnetic field, which is important for the efficiency of electromagnets. <br/> The first statement (I) is not true because iron does not retain its magnetism as long as steel does; steel is more durable in retaining magnetism.</div>", "topic": "MAGNETIC FIELD : ELECTROMAGNETS"}, {"id": "objective>Physics>2003>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of light rays shows the widest separation in the spectrum of white light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Blue and red.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green and yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Indigo and violet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Orange and red</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is a concept in optics which is known as DISPERSION OF WHITE LIGHT. Dispersion of white light occurs when a white light is allowed to pass through a prism and it gets refracted into seven colours (its colourd constituents) <br/>  <br/> R = Red <br/> O = Orange <br/> Y = Yellow <br/> G = Green <br/> B = Blue <br/> I = Indigo <br/> V = Violet <br/> Note: These components of white move at different speed once they get air-glass boundary; and this determines their extent of deviation. In accordance with what we have in the diagram above, red deviated the least because it has the greatest energy while violet deviates the most because it has the least energy. <br/> - Let us focus on the options given <br/> a) This does not follow the order <br/> b) This does not follow the order  <br/> c) It follows the normal pattern, i.e red comes before green, and green comes before blue <br/> d) This does not follow the order <br/>  <br/> </div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2003>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable cell used for short interval switches in electric bells is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lead-acid accumulator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Daniel Cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leclanche Cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nickel-iron accumulator</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Leclanche Cell is the most suitable for short interval switches in electric bells. This is because it has a high internal resistance and low battery capacity, making it ideal for intermittent use. The other cells listed have lower internal resistance and higher capacity, making them more suitable for continuous use.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2003>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ray incident on a glass prism undergoes  minimum deviation when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">incident angle is equal to the angle of refraction.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction angle equals 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">incident angle equals 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">incident angle is equal to the angle of emergence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A ray incident on a glass prison undergoes minimum deviation when the incident angle is equal to the angle of emergence.</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2003>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the calibration of an ammeter using Faraday's law of electrolysis, the  <br/> ammeter reading is kept constant at 1.20A. If 0.990g of copper is deposited  <br/> in 40 minutes, the correction to be applied to the ammeter is  <br/>  <br/>  [e.c.e. of copper = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.30A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.04A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.06A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To get the correction, you must calculate the normal value of the current. The ammeter reading is 1.20A <br/> From Faraday's First Law of Electrolysis <br/> m α Q <br/> m = ZQ ----------------- * <br/> m = ZIt ------------------- * * <br/> 0.99 = 3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> × I × 40 × 60 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span><hr size=\"1\" />3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> × 2400</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <hr size=\"1\" />2.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> I = 1.25A <br/> So a correction of 0.05A should be applied.</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2003>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The count rate of a radioactive material is 800 count/min. If the half-life of the material is 4 days, what would be the count rate 16 days later?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200 count/min</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 count/min</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 count/min</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25 count/min</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>, <br/> Count rate, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 800 count/min  <br/> Half life t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0.5</span> = 4days  <br/> After 16 days count rate will be:  <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span> = N(0)/2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16/t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0.5</span></span> = 800/2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16/4</span> = 800/2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>  <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span> = 800/16 = 50 count/min.</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2003>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A  circuit  has  an  area  of  0.4m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>and consists of 50 loops of wire. If  <br/> the loops are  twisted  and  allowed  to  rotate  at  a constant angular  <br/> velocity of 10 rad s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>in a  uniform  magnetic  field  of  0.4T,  the  <br/> amplitude of the induced voltage is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80V.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">nABV</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">0.4</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">0.4</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80V</td></tr></table></div></div>", "topic": "ELECTROMAGNETIC INDUCTION : FARADAY’S LAWS"}, {"id": "objective>Physics>2003>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the uncertainty in  the measurement of the position of a particle is 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>m,the  uncertainty in the momentum of the particle is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.32 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-44</span>Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-44</span>Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.32 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-24</span>Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-24</span>Ns</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> From Heisenberg principle. Plancks constant h ≥ l.m i.e.position x momentum. <br/>  <br/> 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> = 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> x m ∴ m = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>/5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> = 1.32 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-24</span> Ns</div>", "topic": "ELEMENTARY MODERN PHYSICS : THE UNCERTAINTY PRINCIPLE"}, {"id": "objective>Physics>2003>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force on a charge moving with velocity v in a magnetic field B  <br/> is half of the  momentum force when the angle between v and B is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From: F = BevSinθ --------------------------* <br/> When it is maximumθ = 90°, i.e, sin90° = 1 <br/> when it is 1/2 of the maximum, θ = 30° <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">i.e</td><td style=\"text-align:center;\">sin30°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2003>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum kinetic energy of the photo electrons emitted from a metal surface is 0.34eV. If the work function of  the  metal  surface  is   <br/> 1.83eV, find the stopping potential.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.17V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.49V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.09V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.34V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">eVs = 1/2mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> evs =K.E <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Vs</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.34eV<hr size=\"1\" />e</td></tr></table></div> <br/> Stopping potential = 0.34V</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2003>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an alternating current given by I = 10sin(120π)t passes through a  <br/> 12Ω resistor, the power dissipated in the resistor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1200W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30W</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R ; 10sin (120π) t, R = 12Ω;  <br/> The peak value = 10A; I = 10 sin (120π)t; sin (120π)t = 0.707;  <br/> Irms = 10 x 0.707 = 7.07 A;P = (Irms of peak value)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> x R = 7.07<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> x 12 = 599.82w = 600w.</div>", "topic": "SIMPLE A. C. CIRCUITS : PEAK AND R.M.S. VALUES"}, {"id": "objective>Physics>2003>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a fission process,the decrease in mass is 0.01%. How much energy could  be  obtained from the  fission  of 1.0g of the material?  <br/>  [c = 3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = 0.01% of 1g = 0.01% of 0.001kg = 0.0001 x 0.001kg = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>; C = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s;  <br/> E = mc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>x (3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>= 9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span> x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> = 9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>J</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}, {"id": "objective>Physics>2003>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a semi-conductor junction diode, as the depletion or barrier layer is  forward biased, the layer</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">widens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">narrows</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">widens then narrows</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a semiconductor junction diode, as the depletion or barrier layer is forward biased, the layer narrows.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2003>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electron makes a transition from  a certain energy level ,E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">k</span> to the  ground state E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>.If the frequency of emission is 8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz, the energy emitted is <br/>  <br/>  [h = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.28 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.28 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">19</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">19</span>J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E= hf = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> x 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>J = 5.28 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J</div>", "topic": "ELEMENTARY MODERN PHYSICS : ENERGY LEVELS AND SPECTRA"}, {"id": "objective>Physics>2003>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference between a pure semi-conductor and a pure metal is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metals are harder than semiconductors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">while the resistance of metals decreases with temperature, the reverse is the  case for semi-conductors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the resistance of metals increases with temperature while for semiconductors, it is the reverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals have forbidden gaps while semi-conductors have not</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For pure metals, resistance increases with increase in temperature , while for pure semi conductors, resistance decreases with rise in temperature</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2003>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a nucleus is formed by bringing protons and neutrons  together,   <br/> the actual mass of the formed nucleus is less than the sum of the  <br/> masses of the constituent protons and neutrons. The energy equivalent   <br/> of this mass difference is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lost energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">work function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">binding energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stability energy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy equivalent of the mass difference when a nucleus is formed by bringing protons and neutrons together is known as the binding energy. This is based on Einstein's mass-energy equivalence principle, which states that the energy of an object is equal to the mass of the object times the speed of light squared (E=mc^2). In this case, the 'missing' mass (mass defect) has been converted into energy which holds the nucleus together, hence the term 'binding energy'.</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}];
